function App() {
  return (
    <Router>
      <Routes>
        {/* Halaman Utama (Login) */}
        <Route path="/" element={<Login />} />

        {/* Halaman Dashboard */}
        <Route path="/dashboard" element={<Dashboard />} />

        {/* Halaman Pendaftaran (Sign Up) */}
        <Route path="/register" element={<SignUp />} />
      </Routes>
    </Router>
  );
}

export default App;
